  1→import type { PlanEntry } from "../../core/types.js";
  2→import type {
  3→  ToolCallMeta,
  4→  ToolUpdateMeta,
  5→  ViewerLinks,
  6→} from "../../core/adapter-primitives/format-types.js";
  7→import {
  8→  STATUS_ICONS,
  9→  KIND_ICONS,
 10→} from "../../core/adapter-primitives/format-types.js";
 11→import {
 12→  progressBar,
 13→  formatTokens,
 14→  truncateContent,
 15→  stripCodeFences,
 16→  splitMessage as sharedSplitMessage,
 17→} from "../../core/adapter-primitives/format-utils.js";
 18→import {
 19→  extractContentText,
 20→  formatToolSummary,
 21→  formatToolTitle,
 22→  resolveToolIcon,
 23→} from "../../core/adapter-primitives/message-formatter.js";
 24→import type { DisplayVerbosity } from "../../core/adapter-primitives/format-types.js";
 25→
 26→function formatViewerLinks(links?: ViewerLinks, filePath?: string): string {
 27→  if (!links) return "";
 28→  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
 29→  let text = "\n";
 30→  if (links.file) text += `\n[View ${fileName || "file"}](${links.file})`;
 31→  if (links.diff)
 32→    text += `\n[View diff${fileName ? ` — ${fileName}` : ""}](${links.diff})`;
 33→  return text;
 34→}
 35→
 36→function formatHighDetails(
 37→  rawInput: unknown,
 38→  content: unknown,
 39→  maxLen: number,
 40→): string {
 41→  let text = "";
 42→  if (rawInput) {
 43→    const inputStr =
 44→      typeof rawInput === "string"
 45→        ? rawInput
 46→        : JSON.stringify(rawInput, null, 2);
 47→    if (inputStr && inputStr !== "{}") {
 48→      text += `\n**Input:**\n\`\`\`\n${truncateContent(inputStr, maxLen)}\n\`\`\``;
 49→    }
 50→  }
 51→  const details = stripCodeFences(extractContentText(content));
 52→  if (details) {
 53→    text += `\n**Output:**\n\`\`\`\n${truncateContent(details, maxLen)}\n\`\`\``;
 54→  }
 55→  return text;
 56→}
 57→
 58→export function formatToolCall(
 59→  tool: ToolCallMeta,
 60→  verbosity: DisplayVerbosity = "medium",
 61→): string {
 62→  const si = resolveToolIcon(tool);
 63→  const name = tool.name || "Tool";
 64→  const label =
 65→    verbosity === "low"
 66→      ? formatToolTitle(name, tool.rawInput, tool.displayTitle)
 67→      : formatToolSummary(name, tool.rawInput, tool.displaySummary);
 68→  let text = `${si} **${label}**`;
 69→  // viewer links always shown regardless of verbosity
 70→  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
 71→  // high only: rawInput + content
 72→  if (verbosity === "high") {
 73→    text += formatHighDetails(tool.rawInput, tool.content, 500);
 74→  }
 75→  return text;
 76→}
 77→
 78→export function formatToolUpdate(
 79→  update: ToolUpdateMeta,
 80→  verbosity: DisplayVerbosity = "medium",
 81→): string {
 82→  return formatToolCall(update, verbosity);
 83→}
 84→
 85→export function formatPlan(
 86→  entries: PlanEntry[],
 87→  verbosity: DisplayVerbosity = "medium",
 88→): string {
 89→  // medium: summary count only
 90→  if (verbosity === "medium") {
 91→    const done = entries.filter((e) => e.status === "completed").length;
 92→    return `📋 **Plan:** ${done}/${entries.length} steps completed`;
