  1→// src/adapters/slack/formatter.ts
  2→import type { types } from "@slack/bolt";
  3→import type { OutgoingMessage, PermissionRequest } from "../../core/types.js";
  4→import { splitSafe } from "./utils.js";
  5→
  6→type KnownBlock = types.KnownBlock;
  7→
  8→export interface ISlackFormatter {
  9→  formatOutgoing(message: OutgoingMessage): KnownBlock[];
 10→  formatPermissionRequest(req: PermissionRequest): KnownBlock[];
 11→  formatNotification(text: string): KnownBlock[];
 12→  formatSessionEnd(reason?: string): KnownBlock[];
 13→}
 14→
 15→/**
 16→ * Convert a markdown string to Slack mrkdwn format.
 17→ * Handles the most common patterns from AI responses.
 18→ */
 19→export function markdownToMrkdwn(text: string): string {
 20→  return text
 21→    // Fenced code blocks — preserve as-is (Slack supports ``` natively)
 22→    // Headers: # H1 → placeholder (protected from italic regex)
 23→    .replace(/^#{1,6}\s+(.+)$/gm, "\x00BOLD\x00$1\x00BOLD\x00")
 24→    // Bold: **text** → placeholder
 25→    .replace(/\*\*(.+?)\*\*/g, "\x00BOLD\x00$1\x00BOLD\x00")
 26→    // Italic: *text* → _text_ (won't match placeholder tokens)
 27→    .replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "_$1_")
 28→    // Restore bold/header placeholders → *text*
 29→    .replace(/\x00BOLD\x00(.+?)\x00BOLD\x00/g, "*$1*")
 30→    // Inline code: `code` — kept as-is (Slack supports backtick)
 31→    // Strikethrough: ~~text~~ → ~text~
 32→    .replace(/~~(.+?)~~/g, "~$1~")
 33→    // Links: [text](url) → <url|text>
 34→    .replace(/\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g, "<$2|$1>")
 35→    // Unordered lists: "- item" or "* item" → "• item"
 36→    .replace(/^[ \t]*[-*]\s+/gm, "• ")
 37→    // Ordered lists: "1. item" → "1. item" (already fine in mrkdwn)
 38→    .trim();
 39→}
 40→
 41→// Slack mrkdwn text block, max 3000 chars per section
 42→const SECTION_LIMIT = 3000;
 43→
