import type {
  IChannelAdapter,
  ChannelConfig,
  AdapterCapabilities,
} from '../channel.js'
import type {
  OutgoingMessage,
  PermissionRequest,
  NotificationMessage,
} from '../types.js'
import type { DisplayVerbosity, ToolCallMeta } from './format-types.js'
import type { IRenderer } from './rendering/renderer.js'
import { evaluateNoise } from './message-formatter.js'

export interface AdapterContext {
  configManager: { get(): Record<string, unknown> }
  fileService?: unknown
}

export interface MessagingAdapterConfig extends ChannelConfig {
  maxMessageLength: number
  flushInterval?: number
  sendInterval?: number
  thinkingRefreshInterval?: number
  thinkingDuration?: number
  displayVerbosity?: DisplayVerbosity
}

export interface SentMessage {
  messageId: string
}

const HIDDEN_ON_LOW = new Set(['thought', 'plan', 'usage'])

export abstract class MessagingAdapter implements IChannelAdapter {
  abstract readonly name: string
  abstract readonly renderer: IRenderer
  abstract readonly capabilities: AdapterCapabilities

  constructor(
    protected context: AdapterContext,
    protected adapterConfig: MessagingAdapterConfig,
  ) {}

  // === Message dispatch flow ===

  async sendMessage(sessionId: string, content: OutgoingMessage): Promise<void> {
    const verbosity = this.getVerbosity()
    if (!this.shouldDisplay(content, verbosity)) return
    await this.dispatchMessage(sessionId, content, verbosity)
  }

  protected async dispatchMessage(
    sessionId: string,
    content: OutgoingMessage,
    verbosity: DisplayVerbosity,
  ): Promise<void> {
    switch (content.type) {
      case 'text':           return this.handleText(sessionId, content)
      case 'thought':        return this.handleThought(sessionId, content, verbosity)
      case 'tool_call':      return this.handleToolCall(sessionId, content, verbosity)
      case 'tool_update':    return this.handleToolUpdate(sessionId, content, verbosity)
      case 'plan':           return this.handlePlan(sessionId, content, verbosity)
      case 'usage':          return this.handleUsage(sessionId, content, verbosity)
      case 'error':          return this.handleError(sessionId, content)
      case 'attachment':     return this.handleAttachment(sessionId, content)
      case 'system_message': return this.handleSystem(sessionId, content)
      case 'session_end':    return this.handleSessionEnd(sessionId, content)
      case 'mode_change':    return this.handleModeChange(sessionId, content)
      case 'config_update':  return this.handleConfigUpdate(sessionId, content)
      case 'model_update':   return this.handleModelUpdate(sessionId, content)
      case 'user_replay':    return this.handleUserReplay(sessionId, content)
      case 'resource':       return this.handleResource(sessionId, content)
      case 'resource_link':  return this.handleResourceLink(sessionId, content)
    }
  }

  // === Default handlers — all protected, all overridable ===

  protected async handleText(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleThought(_sessionId: string, _content: OutgoingMessage, _verbosity: DisplayVerbosity): Promise<void> {}
  protected async handleToolCall(_sessionId: string, _content: OutgoingMessage, _verbosity: DisplayVerbosity): Promise<void> {}
  protected async handleToolUpdate(_sessionId: string, _content: OutgoingMessage, _verbosity: DisplayVerbosity): Promise<void> {}
  protected async handlePlan(_sessionId: string, _content: OutgoingMessage, _verbosity: DisplayVerbosity): Promise<void> {}
  protected async handleUsage(_sessionId: string, _content: OutgoingMessage, _verbosity: DisplayVerbosity): Promise<void> {}
  protected async handleError(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleAttachment(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleSystem(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleSessionEnd(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleModeChange(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleConfigUpdate(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleModelUpdate(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleUserReplay(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleResource(_sessionId: string, _content: OutgoingMessage): Promise<void> {}
  protected async handleResourceLink(_sessionId: string, _content: OutgoingMessage): Promise<void> {}

  // === Helpers ===

  protected getVerbosity(): DisplayVerbosity {
    const config = this.context.configManager.get()
    const channelConfig = (config as Record<string, unknown>).channels as Record<string, Record<string, unknown>> | undefined
    const v = channelConfig?.[this.name]?.displayVerbosity ?? this.adapterConfig.displayVerbosity
    if (v === 'low' || v === 'high') return v
    return 'medium'
  }

  protected shouldDisplay(content: OutgoingMessage, verbosity: DisplayVerbosity): boolean {
    if (verbosity === 'low' && HIDDEN_ON_LOW.has(content.type)) return false

    if (content.type === 'tool_call') {
      const meta = (content.metadata ?? {}) as Partial<ToolCallMeta>
      const toolName = meta.name ?? content.text ?? ''
      const toolKind = String(meta.kind ?? 'other')
      const noiseAction = evaluateNoise(toolName, toolKind, meta.rawInput)
      if (noiseAction === 'hide' && verbosity !== 'high') return false
      if (noiseAction === 'collapse' && verbosity === 'low') return false
    }

    return true
  }

  // === Abstract — adapter MUST implement ===

  abstract start(): Promise<void>
  abstract stop(): Promise<void>
  abstract createSessionThread(sessionId: string, name: string): Promise<string>
  abstract renameSessionThread(sessionId: string, newName: string): Promise<void>
  abstract sendPermissionRequest(sessionId: string, request: PermissionRequest): Promise<void>
  abstract sendNotification(notification: NotificationMessage): Promise<void>
}

import type { PlanEntry } from "../../core/types.js";
import type {
  ToolCallMeta,
  ToolUpdateMeta,
  ViewerLinks,
} from "../../core/adapter-primitives/format-types.js";
import {
  STATUS_ICONS,
  KIND_ICONS,
} from "../../core/adapter-primitives/format-types.js";
import {
  progressBar,
  formatTokens,
  truncateContent,
  stripCodeFences,
  splitMessage as sharedSplitMessage,
} from "../../core/adapter-primitives/format-utils.js";
import {
  extractContentText,
  formatToolSummary,
  formatToolTitle,
  resolveToolIcon,
} from "../../core/adapter-primitives/message-formatter.js";
import type { DisplayVerbosity } from "../../core/adapter-primitives/format-types.js";

function formatViewerLinks(links?: ViewerLinks, filePath?: string): string {
  if (!links) return "";
  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
  let text = "\n";
  if (links.file) text += `\n[View ${fileName || "file"}](${links.file})`;
  if (links.diff)
    text += `\n[View diff${fileName ? ` — ${fileName}` : ""}](${links.diff})`;
  return text;
}

function formatHighDetails(
  rawInput: unknown,
  content: unknown,
  maxLen: number,
): string {
  let text = "";
  if (rawInput) {
    const inputStr =
      typeof rawInput === "string"
        ? rawInput
        : JSON.stringify(rawInput, null, 2);
    if (inputStr && inputStr !== "{}") {
      text += `\n**Input:**\n\`\`\`\n${truncateContent(inputStr, maxLen)}\n\`\`\``;
    }
  }
  const details = stripCodeFences(extractContentText(content));
  if (details) {
    text += `\n**Output:**\n\`\`\`\n${truncateContent(details, maxLen)}\n\`\`\``;
  }
  return text;
}

export function formatToolCall(
  tool: ToolCallMeta,
  verbosity: DisplayVerbosity = "medium",
): string {
  const si = resolveToolIcon(tool);
  const name = tool.name || "Tool";
  const label =
    verbosity === "low"
      ? formatToolTitle(name, tool.rawInput, tool.displayTitle)
      : formatToolSummary(name, tool.rawInput, tool.displaySummary);
  let text = `${si} **${label}**`;
  // viewer links always shown regardless of verbosity
  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
  // high only: rawInput + content
  if (verbosity === "high") {
    text += formatHighDetails(tool.rawInput, tool.content, 500);
  }
  return text;
}

export function formatToolUpdate(
  update: ToolUpdateMeta,
  verbosity: DisplayVerbosity = "medium",
): string {
  return formatToolCall(update, verbosity);
}

export function formatPlan(
  entries: PlanEntry[],
  verbosity: DisplayVerbosity = "medium",
): string {
  // medium: summary count only
  if (verbosity === "medium") {
    const done = entries.filter((e) => e.status === "completed").length;
    return `📋 **Plan:** ${done}/${entries.length} steps completed`;
  }
  // high: full entries
  const statusIcon: Record<string, string> = {
    pending: "⏳",
    in_progress: "🔄",
    completed: "✅",
  };
  const lines = entries.map(
    (e, i) => `${statusIcon[e.status] || "⬜"} ${i + 1}. ${e.content}`,
  );
  return `**Plan:**\n${lines.join("\n")}`;
}

export function formatUsage(
  usage: { tokensUsed?: number; contextSize?: number; cost?: number },
  verbosity: DisplayVerbosity = "medium",
): string {
  const { tokensUsed, contextSize, cost } = usage;
  if (tokensUsed == null) return "📊 Usage data unavailable";

  // medium: compact one-line
  if (verbosity === "medium") {
    const costStr = cost != null ? ` · $${cost.toFixed(2)}` : "";
    return `📊 ${formatTokens(tokensUsed)} tokens${costStr}`;
  }

  // high: full progress bar + cost
  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
  const ratio = tokensUsed / contextSize;
  const pct = Math.round(ratio * 100);
  const bar = progressBar(ratio);
  const emoji = pct >= 85 ? "⚠️" : "📊";
  let text = `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
  if (cost != null) text += `\n💰 $${cost.toFixed(2)}`;
  return text;
}

export function splitMessage(text: string, maxLength = 1800): string[] {
  return sharedSplitMessage(text, maxLength);
}

