  6→import {
  7→  STATUS_ICONS,
  8→  KIND_ICONS,
  9→} from "../../core/adapter-primitives/format-types.js";
 10→import {
 11→  progressBar,
 12→  formatTokens,
 13→  truncateContent,
 14→  stripCodeFences,
 15→  splitMessage as sharedSplitMessage,
 16→} from "../../core/adapter-primitives/format-utils.js";
 17→import {
 18→  extractContentText,
 19→  formatToolSummary,
 20→  formatToolTitle,
 21→  resolveToolIcon,
 22→} from "../../core/adapter-primitives/message-formatter.js";
 23→import type { DisplayVerbosity } from "../../core/adapter-primitives/format-types.js";
 24→
 25→export function escapeHtml(text: string | undefined | null): string {
 26→  if (!text) return "";
 27→  return text
 28→    .replace(/&/g, "&amp;")
 29→    .replace(/</g, "&lt;")
 30→    .replace(/>/g, "&gt;");
 31→}
 32→
 33→export function markdownToTelegramHtml(md: string): string {
 34→  // Step 1: Extract code blocks and inline code into placeholders
 35→  const codeBlocks: string[] = [];
 36→  const inlineCodes: string[] = [];
 37→
 38→  // Extract fenced code blocks (```lang\n...\n```)
 39→  let text = md.replace(
 40→    /```(\w*)\n?([\s\S]*?)```/g,
 41→    (_match, lang: string, code: string) => {
 42→      const index = codeBlocks.length;
 43→      const escapedCode = escapeHtml(code);
 44→      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : "";
 45→      codeBlocks.push(`<pre><code${langAttr}>${escapedCode}</code></pre>`);
 46→      return `\x00CODE_BLOCK_${index}\x00`;
 47→    },
 48→  );
 49→
 50→  // Extract inline code (`...`)
 51→  text = text.replace(/`([^`]+)`/g, (_match, code: string) => {
 52→    const index = inlineCodes.length;
 53→    inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
 54→    return `\x00INLINE_CODE_${index}\x00`;
 55→  });
 56→
 57→  // Step 2: Escape HTML in remaining text
 58→  text = escapeHtml(text);
 59→
 60→  // Step 3: Apply markdown transformations
 61→  // Bold: **text** → <b>text</b>
 62→  text = text.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
 63→
 64→  // Italic: *text* → <i>text</i> (but not the ** used for bold)
 65→  text = text.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<i>$1</i>");
 66→
 67→  // Links: [text](url) → <a href="url">text</a>
 68→  // Note: after escapeHtml, parentheses are not affected, but we need to handle
 69→  // the escaped brackets properly. Since [ ] and ( ) are not escaped, this works directly.
 70→  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
 71→
 72→  // Step 4: Restore fenced code blocks
 73→  text = text.replace(/\x00CODE_BLOCK_(\d+)\x00/g, (_match, idx: string) => {
 74→    return codeBlocks[parseInt(idx, 10)];
 75→  });
 76→
 77→  // Step 5: Restore inline code
 78→  text = text.replace(/\x00INLINE_CODE_(\d+)\x00/g, (_match, idx: string) => {
 79→    return inlineCodes[parseInt(idx, 10)];
 80→  });
 81→
 82→  return text;
 83→}
 84→
 85→export function formatToolCall(
 86→  tool: ToolCallMeta,
 87→  verbosity: DisplayVerbosity = "medium",
 88→): string {
 89→  const si = resolveToolIcon(tool);
 90→  const name = tool.name || "Tool";
 91→  const label =
 92→    verbosity === "low"
 93→      ? formatToolTitle(name, tool.rawInput, tool.displayTitle)
 94→      : formatToolSummary(name, tool.rawInput, tool.displaySummary);
 95→  let text = `${si} <b>${escapeHtml(label)}</b>`;
 96→  // viewer links always shown regardless of verbosity
 97→  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
 98→  // high only: rawInput + content
 99→  if (verbosity === "high") {
100→    text += formatHighDetails(tool.rawInput, tool.content, 3800);
101→  }
102→  return text;
103→}
104→
105→export function formatToolUpdate(
106→  update: ToolUpdateMeta,
107→  verbosity: DisplayVerbosity = "medium",
108→): string {
109→  return formatToolCall(update, verbosity);
110→}
111→
112→function formatHighDetails(
113→  rawInput: unknown,
114→  content: unknown,
115→  maxLen: number,
116→): string {
117→  let text = "";
118→  if (rawInput) {
119→    const inputStr =
120→      typeof rawInput === "string"
121→        ? rawInput
122→        : JSON.stringify(rawInput, null, 2);
123→    if (inputStr && inputStr !== "{}") {
124→      text += `\n<b>Input:</b>\n<pre>${escapeHtml(truncateContent(inputStr, maxLen))}</pre>`;
125→    }
126→  }
127→  const details = stripCodeFences(extractContentText(content));
128→  if (details) {
129→    text += `\n<b>Output:</b>\n<pre>${escapeHtml(truncateContent(details, maxLen))}</pre>`;
130→  }
131→  return text;
132→}
133→
134→function formatViewerLinks(links?: ViewerLinks, filePath?: string): string {
135→  if (!links) return "";
136→  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
137→  let text = "\n";
138→  if (links.file)
139→    text += `\n📄 <a href="${escapeHtml(links.file)}">View ${escapeHtml(fileName || "file")}</a>`;
140→  if (links.diff)
141→    text += `\n📝 <a href="${escapeHtml(links.diff)}">View diff${fileName ? ` — ${escapeHtml(fileName)}` : ""}</a>`;
142→  return text;
143→}
144→
145→export function formatPlan(
146→  plan: { entries: Array<{ content: string; status: string }> },
147→  verbosity: DisplayVerbosity = "medium",
148→): string {
149→  const { entries } = plan;
150→  // low/medium: summary count only
151→  if (verbosity === "medium" || verbosity === "low") {
152→    const done = entries.filter((e) => e.status === "completed").length;
153→    return `📋 <b>Plan:</b> ${done}/${entries.length} steps completed`;
154→  }
155→  // high: full entries
156→  const statusIcon: Record<string, string> = {
157→    pending: "⬜",
158→    in_progress: "🔄",
159→    completed: "✅",
160→  };
161→  const lines = entries.map(
162→    (e, i) =>
163→      `${statusIcon[e.status] || "⬜"} ${i + 1}. ${escapeHtml(e.content)}`,
164→  );
165→  return `<b>Plan:</b>\n${lines.join("\n")}`;
166→}
167→
168→export function formatUsage(
169→  usage: { tokensUsed?: number; contextSize?: number; cost?: number },
170→  verbosity: DisplayVerbosity = "medium",
171→): string {
172→  const { tokensUsed, contextSize, cost } = usage;
173→  if (tokensUsed == null) return "📊 Usage data unavailable";
174→
175→  // medium: compact one-line
176→  if (verbosity === "medium") {
177→    const costStr = cost != null ? ` · $${cost.toFixed(2)}` : "";
178→    return `📊 ${formatTokens(tokensUsed)} tokens${costStr}`;
179→  }
180→
181→  // high: full progress bar + cost
182→  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
183→  const ratio = tokensUsed / contextSize;
184→  const pct = Math.round(ratio * 100);
185→  const bar = progressBar(ratio);
186→  const emoji = pct >= 85 ? "⚠️" : "📊";
187→  let text = `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
188→  if (cost != null) text += `\n💰 $${cost.toFixed(2)}`;
189→  return text;
190→}
191→
192→export function formatSummary(summary: string, sessionName?: string): string {
193→  const header = sessionName
194→    ? `📋 <b>Summary — ${escapeHtml(sessionName)}</b>`
195→    : "📋 <b>Session Summary</b>";
196→  return `${header}\n\n${escapeHtml(summary)}`;
197→}
198→
199→export function splitMessage(text: string, maxLength = 3800): string[] {
200→  return sharedSplitMessage(text, maxLength);
201→}
