 58→export function formatToolCall(
 59→  tool: ToolCallMeta,
 60→  verbosity: DisplayVerbosity = "medium",
 61→): string {
 62→  const si = resolveToolIcon(tool);
 63→  const name = tool.name || "Tool";
 64→  const label =
 65→    verbosity === "low"
 66→      ? formatToolTitle(name, tool.rawInput, tool.displayTitle)
 67→      : formatToolSummary(name, tool.rawInput, tool.displaySummary);
 68→  let text = `${si} **${label}**`;
 69→  // viewer links always shown regardless of verbosity
 70→  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
 71→  // high only: rawInput + content
 72→  if (verbosity === "high") {
 73→    text += formatHighDetails(tool.rawInput, tool.content, 500);
 74→  }
 75→  return text;
 76→}
