 78→export function formatToolUpdate(
 79→  update: ToolUpdateMeta,
 80→  verbosity: DisplayVerbosity = "medium",
 81→): string {
 82→  return formatToolCall(update, verbosity);
 83→}
 84→
 85→export function formatPlan(
 86→  entries: PlanEntry[],
 87→  verbosity: DisplayVerbosity = "medium",
 88→): string {
 89→  // low/medium: summary count only
 90→  if (verbosity === "medium" || verbosity === "low") {
 91→    const done = entries.filter((e) => e.status === "completed").length;
 92→    return `📋 **Plan:** ${done}/${entries.length} steps completed`;
 93→  }
 94→  // high: full entries
 95→  const statusIcon: Record<string, string> = {
 96→    pending: "⏳",
 97→    in_progress: "🔄",
 98→    completed: "✅",
 99→  };
100→  const lines = entries.map(
101→    (e, i) => `${statusIcon[e.status] || "⬜"} ${i + 1}. ${e.content}`,
102→  );
103→  return `**Plan:**\n${lines.join("\n")}`;
104→}
105→
106→export function formatUsage(
107→  usage: { tokensUsed?: number; contextSize?: number; cost?: number },
108→  verbosity: DisplayVerbosity = "medium",
109→): string {
110→  const { tokensUsed, contextSize, cost } = usage;
111→  if (tokensUsed == null) return "📊 Usage data unavailable";
112→
113→  // medium: compact one-line
114→  if (verbosity === "medium") {
115→    const costStr = cost != null ? ` · $${cost.toFixed(2)}` : "";
116→    return `📊 ${formatTokens(tokensUsed)} tokens${costStr}`;
117→  }
118→
119→  // high: full progress bar + cost
120→  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
121→  const ratio = tokensUsed / contextSize;
122→  const pct = Math.round(ratio * 100);
123→  const bar = progressBar(ratio);
124→  const emoji = pct >= 85 ? "⚠️" : "📊";
125→  let text = `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
126→  if (cost != null) text += `\n💰 $${cost.toFixed(2)}`;
127→  return text;
128→}
