 3→const DEFAULT_TIMEOUT_MS = 10 * 60 * 1000; // 10 minutes
 4→
 5→/**
 6→ * Encapsulates pending permission state with a typed Promise API.
 7→ */
 8→export class PermissionGate {
 9→  private request?: PermissionRequest;
10→  private resolveFn?: (optionId: string) => void;
11→  private rejectFn?: (reason: Error) => void;
12→  private settled = false;
13→  private timeoutTimer?: ReturnType<typeof setTimeout>;
14→  private timeoutMs: number;
15→
16→  constructor(timeoutMs?: number) {
17→    this.timeoutMs = timeoutMs ?? DEFAULT_TIMEOUT_MS;
18→  }
19→
20→  setPending(request: PermissionRequest): Promise<string> {
21→    this.request = request;
22→    this.settled = false;
23→    this.clearTimeout();
24→
25→    return new Promise<string>((resolve, reject) => {
26→      this.resolveFn = resolve;
27→      this.rejectFn = reject;
28→
29→      this.timeoutTimer = setTimeout(() => {
30→        this.reject("Permission request timed out (no response received)");
31→      }, this.timeoutMs);
32→    });
33→  }
34→
35→  resolve(optionId: string): void {
36→    if (this.settled || !this.resolveFn) return;
37→    this.settled = true;
38→    this.clearTimeout();
39→    this.resolveFn(optionId);
40→    this.cleanup();
41→  }
42→
43→  reject(reason?: string): void {
44→    if (this.settled || !this.rejectFn) return;
45→    this.settled = true;
46→    this.clearTimeout();
47→    this.rejectFn(new Error(reason ?? "Permission rejected"));
48→    this.cleanup();
49→  }
50→
51→  get isPending(): boolean {
52→    return !!this.request && !this.settled;
53→  }
54→
55→  get currentRequest(): PermissionRequest | undefined {
56→    return this.isPending ? this.request : undefined;
57→  }
58→
59→  /** The request ID of the current pending request, undefined after settlement */
60→  get requestId(): string | undefined {
61→    return this.request?.id;
62→  }
63→
64→  private clearTimeout(): void {
65→    if (this.timeoutTimer) {
66→      clearTimeout(this.timeoutTimer);
67→      this.timeoutTimer = undefined;
68→    }
69→  }
70→
71→  private cleanup(): void {
72→    this.request = undefined;
73→    this.resolveFn = undefined;
74→    this.rejectFn = undefined;
75→  }
76→}
