 66→/**
 67→ * Wraps native fetch to work around grammY's polyfilled AbortController.
 68→ * grammY uses abort-controller polyfill whose AbortSignal fails instanceof
 69→ * checks in Node 24+ native fetch. This wrapper re-creates a native
 70→ * AbortSignal from the polyfilled one before passing it to fetch.
 71→ */
 72→function patchedFetch(
 73→  input: RequestInfo | URL,
 74→  init?: RequestInit,
 75→): Promise<Response> {
 76→  if (init?.signal && !(init.signal instanceof AbortSignal)) {
 77→    const nativeController = new AbortController();
 78→    const polyfillSignal = init.signal as unknown as {
 79→      aborted: boolean;
 80→      addEventListener: (event: string, fn: () => void) => void;
 81→    };
 82→    if (polyfillSignal.aborted) {
 83→      nativeController.abort();
 84→    } else {
 85→      polyfillSignal.addEventListener("abort", () => nativeController.abort());
 86→    }
 87→    init = { ...init, signal: nativeController.signal };
 88→  }
 89→  return fetch(input, init);
 90→}
