 4→export function registerHelpCommand(registry: CommandRegistry, _core: unknown): void {
 5→  registry.register({
 6→    name: 'help',
 7→    description: 'Show available commands',
 8→    usage: '[command]',
 9→    category: 'system',
10→    handler: async (args) => {
11→      const query = args.raw.trim()
12→
13→      if (query) {
14→        const cmd = registry.get(query)
15→        if (!cmd) {
16→          return { type: 'error', message: `Unknown command: /${query}` } satisfies CommandResponse
17→        }
18→        let text = `/${cmd.name}`
19→        if (cmd.usage) text += ` ${cmd.usage}`
20→        text += `\n${cmd.description}`
21→        return { type: 'text', text } satisfies CommandResponse
22→      }
23→
24→      // Auto-generate help from registry at invocation time
25→      const systemCmds = registry.getByCategory('system')
26→      const pluginCmds = registry.getByCategory('plugin')
27→
28→      const lines: string[] = []
29→
30→      if (systemCmds.length > 0) {
31→        lines.push('System Commands:')
32→        for (const cmd of systemCmds) {
33→          const usage = cmd.usage ? ` ${cmd.usage}` : ''
34→          lines.push(`  /${cmd.name}${usage} — ${cmd.description}`)
35→        }
36→      }
37→
38→      if (pluginCmds.length > 0) {
39→        if (lines.length > 0) lines.push('')
40→        lines.push('Plugin Commands:')
41→        for (const cmd of pluginCmds) {
42→          const usage = cmd.usage ? ` ${cmd.usage}` : ''
43→          lines.push(`  /${cmd.name}${usage} — ${cmd.description}`)
44→        }
45→      }
46→
47→      if (lines.length === 0) {
48→        return { type: 'text', text: 'No commands registered.' } satisfies CommandResponse
49→      }
50→
51→      return { type: 'text', text: lines.join('\n') } satisfies CommandResponse
52→    },
53→  })
54→}
