 3→/**
 4→ * Serial prompt queue — ensures prompts are processed one at a time.
 5→ */
 6→export class PromptQueue {
 7→  private queue: Array<{ text: string; attachments?: Attachment[]; resolve: () => void }> = []
 8→  private processing = false
 9→  private abortController: AbortController | null = null
10→
11→  constructor(
12→    private processor: (text: string, attachments?: Attachment[]) => Promise<void>,
13→    private onError?: (err: unknown) => void,
14→  ) {}
15→
16→  async enqueue(text: string, attachments?: Attachment[]): Promise<void> {
17→    if (this.processing) {
18→      return new Promise<void>((resolve) => {
19→        this.queue.push({ text, attachments, resolve })
20→      })
21→    }
22→    await this.process(text, attachments)
23→  }
24→
25→  private async process(text: string, attachments?: Attachment[]): Promise<void> {
26→    this.processing = true
27→    this.abortController = new AbortController()
28→    const { signal } = this.abortController
29→    try {
30→      await Promise.race([
31→        this.processor(text, attachments),
32→        new Promise<never>((_, reject) => {
33→          signal.addEventListener('abort', () => reject(new Error('Prompt aborted')), { once: true })
34→        }),
35→      ])
36→    } catch (err) {
37→      // Only forward non-abort errors to onError handler
38→      if (!(err instanceof Error && err.message === 'Prompt aborted')) {
39→        this.onError?.(err)
40→      }
41→    } finally {
42→      this.abortController = null
43→      this.processing = false
44→      this.drainNext()
45→    }
46→  }
47→
48→  private drainNext(): void {
49→    const next = this.queue.shift()
50→    if (next) {
51→      this.process(next.text, next.attachments).then(next.resolve)
52→    }
53→  }
54→
55→  clear(): void {
56→    // Abort the currently running prompt so the queue can drain
57→    if (this.abortController) {
58→      this.abortController.abort()
59→    }
60→    // Resolve pending promises so callers don't hang
61→    for (const item of this.queue) {
62→      item.resolve()
63→    }
64→    this.queue = []
65→  }
66→
67→  get pending(): number {
68→    return this.queue.length
69→  }
70→
71→  get isProcessing(): boolean {
72→    return this.processing
73→  }
74→}
