 28→  log.info({ sessionId: session.id }, "Assistant agent spawned");
 29→
 30→  // Build dynamic context for system prompt
 31→  const allRecords = core.sessionManager.listRecords();
 32→  const activeCount = allRecords.filter(r => r.status === 'active' || r.status === 'initializing').length;
 33→  const statusCounts = new Map<string, number>();
 34→  for (const r of allRecords) {
 35→    statusCounts.set(r.status, (statusCounts.get(r.status) ?? 0) + 1);
 36→  }
 37→  const topicSummary = Array.from(statusCounts.entries()).map(([status, count]) => ({ status, count }));
 38→
 39→  // Get agent info from catalog
 40→  const installedAgents = Object.keys(core.agentCatalog.getInstalledEntries());
 41→  const availableItems = core.agentCatalog.getAvailable();
 42→  const availableAgentCount = availableItems.filter(i => !i.installed).length;
 43→
 44→  const ctx: AssistantContext = {
 45→    config,
 46→    activeSessionCount: activeCount,
 47→    totalSessionCount: allRecords.length,
 48→    topicSummary,
 49→    installedAgents,
 50→    availableAgentCount,
 51→  };
 52→
 53→  // Fire system prompt in background — don't block startup.
 54→  const systemPrompt = buildAssistantSystemPrompt(ctx);
 55→  const ready = session.enqueuePrompt(systemPrompt)
 56→    .then(() => { log.info({ sessionId: session.id }, "Assistant system prompt completed"); })
 57→    .catch((err) => { log.warn({ err }, "Assistant system prompt failed"); });
 58→
 59→  return { session, ready };
 60→}
 61→
 62→export interface AssistantContext {
 63→  config: Config
 64→  activeSessionCount: number
 65→  totalSessionCount: number
 66→  topicSummary: { status: string; count: number }[]
 67→  installedAgents?: string[]
 68→  availableAgentCount?: number
 69→}
