 79→export function buildWelcomeMessage(ctx: WelcomeContext): string {
 80→  const { activeCount, errorCount, totalCount, agents, defaultAgent } = ctx;
 81→
 82→  const agentList = agents
 83→    .map((a) => `${a}${a === defaultAgent ? " (default)" : ""}`)
 84→    .join(", ");
 85→
 86→  // Variant 1: No sessions
 87→  if (totalCount === 0) {
 88→    return `👋 <b>OpenACP is ready!</b>\n\nNo sessions yet. Tap 🆕 New Session to start, or ask me anything!`;
 89→  }
 90→
 91→  // Variant 2: Has errors
 92→  if (errorCount > 0) {
 93→    return (
 94→      `👋 <b>OpenACP is ready!</b>\n\n` +
 95→      `📊 ${activeCount} active, ${errorCount} errors / ${totalCount} total\n` +
 96→      `⚠️ ${errorCount} session${errorCount > 1 ? "s have" : " has"} errors — ask me to check if you'd like.\n\n` +
 97→      `Agents: ${agentList}`
 98→    );
 99→  }
