164→// ─── PlanCard ─────────────────────────────────────────────────────────────────
165→
166→function formatPlanCard(
167→  entries: PlanEntry[],
168→  verbosity: DisplayVerbosity = "medium",
169→): string {
170→  if (verbosity === "medium") {
171→    const done = entries.filter((e) => e.status === "completed").length;
172→    return `📋 <b>Plan:</b> ${done}/${entries.length} steps completed`;
173→  }
174→  const statusIcon: Record<string, string> = {
175→    completed: "✅",
176→    in_progress: "🔄",
177→    pending: "⬜",
178→    failed: "❌",
179→  };
180→  const total = entries.length;
181→  const done = entries.filter((e) => e.status === "completed").length;
182→  const ratio = total > 0 ? done / total : 0;
183→  const filled = Math.round(ratio * 10);
184→  const bar = "▓".repeat(filled) + "░".repeat(10 - filled);
185→  const pct = Math.round(ratio * 100);
186→  const header = `📋 <b>Plan</b>\n${bar} ${pct}% · ${done}/${total}`;
187→  const lines = entries.map((e, i) => {
188→    const icon = statusIcon[e.status] ?? "⬜";
189→    return `${icon} ${i + 1}. ${e.content}`;
190→  });
191→  return [header, ...lines].join("\n");
192→}
193→
194→export class PlanCard {
195→  private msgId?: number;
196→  private flushPromise: Promise<void> = Promise.resolve();
197→  private latestEntries?: PlanEntry[];
198→  private lastSentText?: string;
199→  private flushTimer?: ReturnType<typeof setTimeout>;
200→  private verbosity: DisplayVerbosity = "medium";
201→
202→  constructor(
203→    private api: Bot["api"],
204→    private chatId: number,
205→    private threadId: number,
206→    private sendQueue: SendQueue,
207→  ) {}
208→
209→  setVerbosity(v: DisplayVerbosity): void {
210→    this.verbosity = v;
211→  }
212→
213→  update(entries: PlanEntry[]): void {
214→    this.latestEntries = entries;
215→    if (this.flushTimer) clearTimeout(this.flushTimer);
216→    this.flushTimer = setTimeout(() => {
217→      this.flushTimer = undefined;
218→      this.flushPromise = this.flushPromise
219→        .then(() => this._flush())
220→        .catch(() => {});
221→    }, 3500);
222→  }
223→
224→  async finalize(): Promise<void> {
225→    if (!this.latestEntries) return;
226→    if (this.flushTimer) {
227→      clearTimeout(this.flushTimer);
228→      this.flushTimer = undefined;
229→    }
230→    await this.flushPromise;
231→    this.flushPromise = this.flushPromise
232→      .then(() => this._flush())
233→      .catch(() => {});
234→    await this.flushPromise;
235→  }
236→
237→  destroy(): void {
238→    if (this.flushTimer) {
239→      clearTimeout(this.flushTimer);
240→      this.flushTimer = undefined;
241→    }
242→  }
243→
244→  private async _flush(): Promise<void> {
245→    if (!this.latestEntries) return;
246→    const text = formatPlanCard(this.latestEntries, this.verbosity);
247→    if (this.msgId && text === this.lastSentText) return;
248→    this.lastSentText = text;
249→    try {
250→      if (this.msgId) {
251→        await this.sendQueue.enqueue(() =>
252→          this.api.editMessageText(this.chatId, this.msgId!, text, {
253→            parse_mode: "HTML",
254→          }),
255→        );
256→      } else {
257→        const result = await this.sendQueue.enqueue(() =>
258→          this.api.sendMessage(this.chatId, text, {
259→            message_thread_id: this.threadId,
260→            parse_mode: "HTML",
261→            disable_notification: true,
262→          }),
263→        );
264→        if (result) this.msgId = result.message_id;
265→      }
266→    } catch (err) {
267→      log.warn({ err }, "PlanCard flush failed");
268→    }
269→  }
270→}
