272→// ─── ActivityTracker ──────────────────────────────────────────────────────────
273→
274→export class ActivityTracker {
275→  private isFirstEvent = true;
276→  private hasPlanCard = false;
277→  private thinking: ThinkingIndicator;
278→  private planCard: PlanCard;
279→  private usage: UsageMessage;
280→
281→  constructor(
282→    private api: Bot["api"],
283→    private chatId: number,
284→    private threadId: number,
285→    private sendQueue: SendQueue,
286→  ) {
287→    this.thinking = new ThinkingIndicator(api, chatId, threadId, sendQueue);
288→    this.planCard = new PlanCard(api, chatId, threadId, sendQueue);
289→    this.usage = new UsageMessage(api, chatId, threadId, sendQueue);
290→  }
291→
292→  async onNewPrompt(): Promise<void> {
293→    this.isFirstEvent = true;
294→    this.hasPlanCard = false;
295→    this.thinking.dismiss();
296→    this.thinking.reset();
297→  }
298→
299→  async onThought(): Promise<void> {
300→    await this._firstEventGuard();
301→    await this.thinking.show();
302→  }
303→
304→  async onPlan(
305→    entries: PlanEntry[],
306→    verbosity?: DisplayVerbosity,
307→  ): Promise<void> {
308→    await this._firstEventGuard();
309→    this.thinking.dismiss();
310→    this.hasPlanCard = true;
311→    if (verbosity) this.planCard.setVerbosity(verbosity);
312→    this.planCard.update(entries);
313→  }
314→
315→  async onToolCall(): Promise<void> {
316→    await this._firstEventGuard();
317→    this.thinking.dismiss();
318→    this.thinking.reset();
319→  }
320→
321→  async onTextStart(): Promise<void> {
322→    await this._firstEventGuard();
323→    this.thinking.dismiss();
324→  }
325→
326→  async sendUsage(
327→    data: { tokensUsed?: number; contextSize?: number; cost?: number },
328→    verbosity: DisplayVerbosity = "medium",
329→  ): Promise<void> {
330→    await this.usage.send(data, verbosity);
331→  }
332→
333→  getUsageMsgId(): number | undefined {
334→    return this.usage.getMsgId();
335→  }
336→
337→  async onComplete(): Promise<void> {
338→    if (this.hasPlanCard) {
339→      await this.planCard.finalize();
340→    } else {
341→      try {
342→        await this.sendQueue.enqueue(() =>
343→          this.api.sendMessage(this.chatId, "✅ <b>Done</b>", {
344→            message_thread_id: this.threadId,
345→            parse_mode: "HTML",
346→            disable_notification: true,
347→          }),
348→        );
349→      } catch (err) {
350→        log.warn({ err }, "ActivityTracker.onComplete() Done send failed");
351→      }
352→    }
353→  }
354→
355→  destroy(): void {
356→    this.thinking.dismiss();
357→    this.planCard.destroy();
358→  }
359→
360→  private async _firstEventGuard(): Promise<void> {
361→    if (!this.isFirstEvent) return;
362→    this.isFirstEvent = false;
363→    await this.usage.delete();
364→  }
365→}
