 12→const THINKING_REFRESH_MS = 15_000;
 13→const THINKING_MAX_MS = 3 * 60 * 1000;
 14→
 15→export class ThinkingIndicator {
 16→  private msgId?: number;
 17→  private sending = false;
 18→  private dismissed = false;
 19→  private refreshTimer?: ReturnType<typeof setInterval>;
 20→  private showTime = 0;
 21→
 22→  constructor(
 23→    private api: Bot["api"],
 24→    private chatId: number,
 25→    private threadId: number,
 26→    private sendQueue: SendQueue,
 27→  ) {}
 28→
 29→  async show(): Promise<void> {
 30→    if (this.msgId || this.sending || this.dismissed) return;
 31→    this.sending = true;
 32→    this.showTime = Date.now();
 33→    try {
 34→      const result = await this.sendQueue.enqueue(() =>
 35→        this.api.sendMessage(this.chatId, "💭 <i>Thinking...</i>", {
 36→          message_thread_id: this.threadId,
 37→          parse_mode: "HTML",
 38→          disable_notification: true,
 39→        }),
 40→      );
 41→      if (result && !this.dismissed) {
 42→        this.msgId = result.message_id;
 43→        this.startRefreshTimer();
 44→      }
 45→    } catch (err) {
 46→      log.warn({ err }, "ThinkingIndicator.show() failed");
 47→    } finally {
 48→      this.sending = false;
 49→    }
 50→  }
 51→
 52→  /** Clear state — stops refresh timer, no Telegram API call */
 53→  dismiss(): void {
 54→    this.dismissed = true;
 55→    this.msgId = undefined;
 56→    this.stopRefreshTimer();
 57→  }
 58→
 59→  /** Reset for a new prompt cycle */
 60→  reset(): void {
 61→    this.dismissed = false;
 62→  }
 63→
 64→  private startRefreshTimer(): void {
 65→    this.stopRefreshTimer();
 66→    this.refreshTimer = setInterval(() => {
 67→      if (
 68→        this.dismissed ||
 69→        !this.msgId ||
 70→        Date.now() - this.showTime >= THINKING_MAX_MS
 71→      ) {
 72→        this.stopRefreshTimer();
