    25→export function escapeHtml(text: string | undefined | null): string {
    26→  if (!text) return "";
    27→  return text
    28→    .replace(/&/g, "&amp;")
    29→    .replace(/</g, "&lt;")
    30→    .replace(/>/g, "&gt;");
