    (e) => e.status === "completed" || e.status === "done" || e.status === "failed",
  );
  const running = visible.filter(
    (e) => e.status !== "completed" && e.status !== "done" && e.status !== "failed",
  );

  for (const entry of completed) {
    let line = `${entry.icon} ${escapeHtml(entry.label)}`;
