   214→  // ─── Interaction handler ──────────────────────────────────────────────────
   215→
   216→  private getCommandRegistry(): CommandRegistry | undefined {
   217→    return this.core.lifecycleManager?.serviceRegistry?.get<CommandRegistry>("command-registry");
   218→  }
   219→
   220→  private setupInteractionHandler(): void {
   221→    this.client.on("interactionCreate", async (interaction) => {
   222→      try {
   223→        // --- Generic CommandRegistry dispatch (slash commands) ---
   224→        if (interaction.isChatInputCommand()) {
   225→          const registry = this.getCommandRegistry();
   226→          if (registry) {
   227→            const commandName = interaction.commandName;
   228→            const def = registry.get(commandName);
   229→            if (def) {
   230→              const rawParts: string[] = [];
   231→              for (const opt of interaction.options.data) {
   232→                rawParts.push(String(opt.value ?? ""));
   233→              }
   234→
   235→              const channelId = interaction.channelId;
   236→              const sessionId =
   237→                this.core.sessionManager.getSessionByThread("discord", channelId)?.id ?? null;
   238→
   239→              const response = await registry.execute(
   240→                `/${commandName} ${rawParts.join(" ")}`.trim(),
   241→                {
   242→                  raw: "",
   243→                  sessionId,
   244→                  channelId: "discord",
   245→                  userId: interaction.user.id,
   246→                  options: Object.fromEntries(
   247→                    interaction.options.data.map((o) => [o.name, String(o.value ?? "")]),
   248→                  ),
   249→                  reply: async (content) => {
   250→                    if (typeof content === "string") {
   251→                      if (interaction.replied || interaction.deferred) {
   252→                        await interaction.editReply({ content });
   253→                      } else {
   254→                        await interaction.reply({ content });
   255→                      }
   256→                    }
   257→                  },
   258→                },
   259→              );
   260→
   261→              if (response.type !== "silent") {
   262→                await this.renderCommandResponse(response, interaction);
   263→              } else if (!interaction.replied && !interaction.deferred) {
   264→                await interaction.deferReply();
   265→              }
   266→              return; // handled by registry
   267→            }
   268→          }
   269→
   270→          // Fall through to existing slash command router
   271→          await handleSlashCommand(interaction, this);
   272→          return;
   273→        }
   274→
   275→        // --- Button interactions ---
   276→        if (interaction.isButton()) {
   277→          // Command registry buttons (c/ prefix) — check before permission/legacy
   278→          if (interaction.customId.startsWith("c/")) {
   279→            const registry = this.getCommandRegistry();
   280→            if (registry) {
   281→              const command = interaction.customId.slice(2);
   282→              const channelId = interaction.channelId;
   283→              const sessionId =
   284→                this.core.sessionManager.getSessionByThread("discord", channelId)?.id ?? null;
   285→
   286→              const response = await registry.execute(command, {
   287→                raw: "",
   288→                sessionId,
   289→                channelId: "discord",
   290→                userId: interaction.user.id,
   291→                reply: async (content) => {
   292→                  if (typeof content === "string") {
   293→                    if (interaction.replied || interaction.deferred) {
   294→                      await interaction.editReply({ content });
   295→                    } else {
   296→                      await interaction.reply({ content, ephemeral: true });
   297→                    }
   298→                  }
   299→                },
   300→              });
   301→
   302→              if (response.type !== "silent") {
   303→                await this.renderCommandResponse(response, interaction);
   304→              }
   305→              return;
   306→            }
   307→          }
   308→
   309→          // Permission buttons take priority over legacy
   310→          const handled =
   311→            await this.permissionHandler.handleButtonInteraction(interaction);
   312→          if (!handled) {
   313→            await setupButtonCallbacks(interaction, this);
   314→          }
   315→        }
   316→      } catch (err) {
   317→        log.error({ err }, "[DiscordAdapter] interactionCreate handler error");
   318→      }
   319→    });
   320→  }
   321→
   322→  // ─── CommandRegistry response rendering ──────────────────────────────────
   323→
   324→  private async renderCommandResponse(
   325→    response: CommandResponse,
   326→    interaction: import("discord.js").ChatInputCommandInteraction | import("discord.js").ButtonInteraction | import("discord.js").StringSelectMenuInteraction,
   327→  ): Promise<void> {
   328→    const reply = async (opts: Record<string, unknown>) => {
   329→      if (interaction.replied || interaction.deferred) {
   330→        await interaction.editReply(opts);
   331→      } else {
   332→        await interaction.reply(opts);
   333→      }
   334→    };
   335→
   336→    switch (response.type) {
   337→      case "text":
   338→        await reply({ content: response.text });
   339→        break;
   340→      case "error":
   341→        await reply({ content: `\u26a0\ufe0f ${response.message}`, ephemeral: true });
   342→        break;
   343→      case "menu": {
   344→        const { ActionRowBuilder, ButtonBuilder, ButtonStyle, EmbedBuilder } =
   345→          await import("discord.js");
   346→        const embed = new EmbedBuilder().setTitle(response.title);
   347→        const rows: InstanceType<typeof ActionRowBuilder>[] = [];
   348→        // Max 5 buttons per row, max 5 rows
   349→        for (let i = 0; i < response.options.length && rows.length < 5; i += 5) {
   350→          const row = new ActionRowBuilder();
   351→          const slice = response.options.slice(i, i + 5);
   352→          for (const opt of slice) {
   353→            row.addComponents(
   354→              new ButtonBuilder()
   355→                .setCustomId(`c/${opt.command}`)
   356→                .setLabel(opt.label.slice(0, 80))
   357→                .setStyle(ButtonStyle.Secondary),
   358→            );
   359→          }
   360→          rows.push(row);
   361→        }
   362→        await reply({ embeds: [embed], components: rows });
   363→        break;
   364→      }
   365→      case "list": {
   366→        const { EmbedBuilder } = await import("discord.js");
   367→        const desc = response.items
   368→          .map((i) => `\u2022 **${i.label}**${i.detail ? ` \u2014 ${i.detail}` : ""}`)
   369→          .join("\n");
   370→        const embed = new EmbedBuilder()
   371→          .setTitle(response.title)
   372→          .setDescription(desc);
   373→        await reply({ embeds: [embed] });
   374→        break;
   375→      }
   376→      case "confirm": {
   377→        const { ActionRowBuilder, ButtonBuilder, ButtonStyle } =
   378→          await import("discord.js");
   379→        const row = new ActionRowBuilder().addComponents(
   380→          new ButtonBuilder()
   381→            .setCustomId(`c/${response.onYes}`)
   382→            .setLabel("Yes")
   383→            .setStyle(ButtonStyle.Success),
   384→          new ButtonBuilder()
   385→            .setCustomId(`c/${response.onNo || "noop"}`)
   386→            .setLabel("No")
   387→            .setStyle(ButtonStyle.Secondary),
   388→        );
   389→        await reply({ content: response.question, components: [row] });
   390→        break;
   391→      }
   392→      case "silent":
   393→        break;
   394→    }
   395→  }
