   397→  // ─── Message handler ──────────────────────────────────────────────────────
   398→
   399→  private setupMessageHandler(): void {
   400→    this.client.on("messageCreate", async (message) => {
   401→      try {
   402→        // Ignore bots and self
   403→        if (message.author.bot) return;
   404→
   405→        // Ignore DMs
   406→        if (!message.guild) return;
   407→
   408→        // Ignore messages from the wrong guild
   409→        if (message.guild.id !== this.guild.id) return;
   410→
   411→        // Only process messages in threads
   412→        if (!message.channel.isThread()) return;
   413→
   414→        const threadId = message.channel.id;
   415→        const userId = message.author.id;
   416→        let text = message.content;
   417→
   418→        log.debug(
   419→          {
   420→            threadId,
   421→            userId,
   422→            text: text.slice(0, 50),
   423→            attachmentCount: message.attachments.size,
   424→          },
   425→          "[DiscordAdapter] messageCreate received",
   426→        );
   427→
   428→        // Ignore messages with no text and no attachments
   429→        if (!text && message.attachments.size === 0) return;
   430→
   431→        // Resolve sessionId for file storage (fallback to "unknown" for new sessions)
   432→        const sessionId =
   433→          this.core.sessionManager.getSessionByThread("discord", threadId)
   434→            ?.id ?? "unknown";
   435→
   436→        // Process attachments
   437→        if (message.attachments.size > 0) {
   438→          log.info(
   439→            {
   440→              sessionId,
   441→              attachments: message.attachments.map((a) => ({
   442→                name: a.name,
   443→                size: a.size,
   444→                contentType: a.contentType,
   445→                url: a.url?.slice(0, 80),
   446→              })),
   447→            },
   448→            "[discord-media] Processing incoming attachments",
   449→          );
   450→        }
   451→        const attachments = await this.processIncomingAttachments(
   452→          message,
   453→          sessionId,
   454→        );
   455→
   456→        // Generate fallback text if message has attachments but no text
   457→        if (!text && attachments.length > 0) {
   458→          text = buildFallbackText(attachments);
   459→        }
   460→
   461→        // If all attachment downloads failed and no text, notify user
   462→        if (!text && attachments.length === 0 && message.attachments.size > 0) {
   463→          try {
   464→            await message.reply("Failed to process attachment(s)");
   465→          } catch {
   466→            /* best effort */
   467→          }
   468→          return;
   469→        }
   470→
   471→        // Route assistant thread messages to assistant
   472→        if (
   473→          this.discordConfig.assistantThreadId &&
   474→          threadId === this.discordConfig.assistantThreadId
   475→        ) {
   476→          if (this.assistantSession && text) {
   477→            await this.assistantSession.enqueuePrompt(
   478→              text,
   479→              attachments.length > 0 ? attachments : undefined,
   480→            );
   481→          }
   482→          return;
   483→        }
   484→
   485→        // Route to core for session dispatch
   486→        await this.core.handleMessage({
   487→          channelId: "discord",
   488→          threadId,
   489→          userId,
   490→          text,
   491→          ...(attachments.length > 0 ? { attachments } : {}),
   492→        });
   493→      } catch (err) {
   494→        log.error({ err }, "[DiscordAdapter] messageCreate handler error");
   495→      }
   496→    });
   497→  }
