   499→  // ─── Assistant ────────────────────────────────────────────────────────────
   500→
   501→  private async setupAssistant(): Promise<void> {
   502→    let threadId = this.discordConfig.assistantThreadId;
   503→
   504→    // Verify existing thread is still accessible
   505→    if (threadId) {
   506→      try {
   507→        const existing =
   508→          this.guild.channels.cache.get(threadId) ??
   509→          (await this.guild.channels.fetch(threadId));
   510→        if (existing && existing.isThread()) {
   511→          await ensureUnarchived(
   512→            existing as import("discord.js").ThreadChannel,
   513→          );
   514→          log.info(
   515→            { threadId },
   516→            "[DiscordAdapter] Reusing existing assistant thread",
   517→          );
   518→        } else {
   519→          log.warn(
   520→            { threadId },
   521→            "[DiscordAdapter] Assistant thread not found, recreating...",
   522→          );
   523→          threadId = null;
   524→        }
   525→      } catch {
   526→        log.warn(
   527→          { threadId },
   528→          "[DiscordAdapter] Assistant thread inaccessible, recreating...",
   529→        );
   530→        threadId = null;
   531→      }
   532→    }
   533→
   534→    if (!threadId) {
   535→      // Create a new thread for the assistant
   536→      const thread = await forumsCreateThread(this.forumChannel, "Assistant");
   537→      threadId = thread.id;
   538→      await this.core.configManager.save({
   539→        channels: { discord: { assistantThreadId: thread.id } },
   540→      } as Parameters<typeof this.core.configManager.save>[0]);
   541→      log.info({ threadId }, "[DiscordAdapter] Created assistant thread");
   542→    }
   543→
   544→    this.assistantInitializing = true;
   545→    try {
   546→      const { session, ready } = await spawnAssistant(this.core, threadId);
   547→      this.assistantSession = session;
   548→      ready.finally(() => {
   549→        this.assistantInitializing = false;
   550→      });
   551→    } catch (err) {
   552→      this.assistantInitializing = false;
   553→      log.error({ err }, "[DiscordAdapter] Failed to spawn assistant");
   554→    }
   555→  }
   556→
   557→  async respawnAssistant(): Promise<void> {
   558→    if (this.assistantSession) {
   559→      try {
   560→        await this.assistantSession.destroy();
   561→      } catch {
   562→        /* ignore */
   563→      }
   564→      this.assistantSession = null;
   565→    }
   566→    await this.setupAssistant();
   567→  }
