   569→  // ─── Incoming media ──────────────────────────────────────────────────
   570→
   571→  private async processIncomingAttachments(
   572→    message: import("discord.js").Message,
   573→    sessionId: string,
   574→  ): Promise<Attachment[]> {
   575→    if (message.attachments.size === 0) return [];
   576→
   577→    const isVoiceMessage = message.flags.has(MessageFlags.IsVoiceMessage);
   578→
   579→    const results = await Promise.allSettled(
   580→      message.attachments.map(async (discordAtt) => {
   581→        const buffer = await downloadDiscordAttachment(
   582→          discordAtt.url,
   583→          discordAtt.name ?? "attachment",
   584→        );
   585→        if (!buffer) return null;
   586→
   587→        let data = buffer;
   588→        let fileName = discordAtt.name ?? "attachment";
   589→        let mimeType = discordAtt.contentType ?? "application/octet-stream";
   590→
   591→        // Convert voice messages from OGG Opus to WAV
   592→        if (isVoiceMessage && mimeType.includes("ogg")) {
   593→          try {
   594→            data = await this.fileService.convertOggToWav(buffer);
   595→            fileName = "voice.wav";
   596→            mimeType = "audio/wav";
   597→          } catch (err) {
   598→            log.warn(
   599→              { err },
   600→              "[discord-media] OGG→WAV conversion failed, saving original",
   601→            );
   602→          }
   603→        }
   604→
   605→        return this.fileService.saveFile(sessionId, fileName, data, mimeType);
   606→      }),
   607→    );
   608→
   609→    const rejected = results.filter((r) => r.status === "rejected");
   610→    if (rejected.length > 0) {
   611→      log.warn(
   612→        { rejected: rejected.map((r) => (r as PromiseRejectedResult).reason) },
   613→        "[discord-media] Some attachments failed",
   614→      );
   615→    }
   616→
   617→    const saved = results
   618→      .filter(
   619→        (r): r is PromiseFulfilledResult<Attachment | null> =>
   620→          r.status === "fulfilled",
   621→      )
   622→      .map((r) => r.value)
   623→      .filter((att): att is Attachment => att !== null);
   624→
   625→    log.info(
   626→      { count: saved.length, files: saved.map((a) => a.fileName) },
   627→      "[discord-media] Attachments processed",
   628→    );
   629→    return saved;
   630→  }
   631→
   632→  // ─── Helper: resolve thread ───────────────────────────────────────────────
   633→
   634→  private async getThread(sessionId: string): Promise<ThreadChannel | null> {
   635→    const session = this.core.sessionManager.getSession(sessionId);
   636→    const threadId = session?.threadId;
   637→    if (!threadId) {
   638→      log.warn({ sessionId }, "[DiscordAdapter] No threadId for session");
   639→      return null;
   640→    }
   641→    try {
   642→      const channel =
   643→        this.guild.channels.cache.get(threadId) ??
   644→        (await this.guild.channels.fetch(threadId));
   645→      if (channel && channel.isThread()) return channel as ThreadChannel;
   646→      log.warn(
   647→        { sessionId, threadId },
   648→        "[DiscordAdapter] Channel is not a thread",
   649→      );
   650→      return null;
   651→    } catch (err) {
   652→      log.warn(
   653→        { err, sessionId, threadId },
   654→        "[DiscordAdapter] Failed to fetch thread",
   655→      );
   656→      return null;
   657→    }
   658→  }
   659→
   660→  // ─── Helper: get or create activity tracker ──────────────────────────────
   661→
   662→  private getOrCreateTracker(
   663→    sessionId: string,
   664→    thread: ThreadChannel,
   665→  ): ActivityTracker {
   666→    if (!this.sessionTrackers.has(sessionId)) {
   667→      this.sessionTrackers.set(
   668→        sessionId,
   669→        new ActivityTracker(thread, this.sendQueue),
   670→      );
   671→    }
   672→    return this.sessionTrackers.get(sessionId)!;
   673→  }
   674→
   675→  private getSessionContext(sessionId: string): { thread: ThreadChannel; isAssistant: boolean } {
   676→    const ctx = this._sessionContexts.get(sessionId);
   677→    if (!ctx) {
   678→      throw new Error(`No thread context stored for session ${sessionId}`);
   679→    }
   680→    return ctx;
   681→  }
   682→
   683→  // ─── sendMessage ──────────────────────────────────────────────────────────
   684→
   685→  async sendMessage(
   686→    sessionId: string,
   687→    content: OutgoingMessage,
   688→  ): Promise<void> {
   689→    // Suppress output while assistant is initializing its system prompt
   690→    if (
   691→      this.assistantInitializing &&
   692→      this.assistantSession &&
   693→      sessionId === this.assistantSession.id
   694→    ) {
   695→      return;
   696→    }
   697→
   698→    const thread = await this.getThread(sessionId);
   699→    if (!thread) return;
   700→
   701→    await ensureUnarchived(thread);
   702→
   703→    // Store thread context keyed by sessionId for concurrency safety
   704→    this._sessionContexts.set(sessionId, {
   705→      thread,
   706→      isAssistant: this.assistantSession != null && sessionId === this.assistantSession.id,
   707→    });
   708→
   709→    try {
   710→      await super.sendMessage(sessionId, content);
   711→    } finally {
   712→      this._sessionContexts.delete(sessionId);
   713→    }
   714→  }
