   871→  protected async handleAttachment(sessionId: string, content: OutgoingMessage): Promise<void> {
   872→    if (!content.attachment) return;
   873→    const { attachment } = content;
   874→    const { thread, isAssistant } = this.getSessionContext(sessionId);
