   880→
   881→    // Discord free tier limit: 25MB
   882→    if (isAttachmentTooLarge(attachment.size)) {
   883→      log.warn(
   884→        {
   885→          sessionId,
   886→          fileName: attachment.fileName,
   887→          size: attachment.size,
